("TextLabel") SubTag.Size = UDim2.new(1, 0, 0, 20) SubTag.Position = UDim2.new(0, 0, 0, 30) SubTag.BackgroundTransparency = 1 SubTag.Text = "M.3/19 #20" SubTag.TextColor3 = Color3.fromRGB(100, 100, 100) SubTag.Font = Enum.Font.Gotham SubTag.TextSize = 12 SubTag.Parent = Sidebar local Content = Instance.new("ScrollingFrame") Content.Size = UDim2.new(1, -130, 1, -20) Content.Position = UDim2.new(0, 125, 0, 10) Content.BackgroundTransparency = 1 Content.CanvasSize = UDim2.new(0, 0, 2, 0) Content.ScrollBarThickness = 2 Content.ScrollBarImageColor3 = Color3.fromRGB(255, 0, 0) Content.Parent = Main local UIList = Instance.new("UIListLayout") UIList.Padding = UDim.new(0, 8) UIList.HorizontalAlignment = Enum.HorizontalAlignment.Center UIList.Parent = Content local function CreateHack(name, desc) local Frame = Instance.new("Frame") Frame.Size = UDim2.new(0.95, 0, 0, 50) Frame.BackgroundColor3 = Color3.fromRGB(20, 20, 20) Frame.Parent = Content local fCorner = Instance.new("UICorner") fCorner.Parent = Frame local fStroke = Instance.new("UIStroke") fStroke.Color = Color3.fromRGB(40, 0, 0) fStroke.Parent = Frame local bName = Instance.new("TextLabel") bName.Size = UDim2.new(0.7, 0, 0.6, 0) bName.Position = UDim2.new(0.05, 0, 0.1, 0) bName.BackgroundTransparency = 1 bName.Text = name bName.TextColor3 = Color3.fromRGB(255, 255, 255) bName.Font = Enum.Font.GothamBold bName.TextSize = 14 bName.TextXAlignment = Enum.TextXAlignment.Left bName.Parent = Frame local bDesc = Instance.new("TextLabel") bDesc.Size = UDim2.new(0.7, 0, 0.3, 0) bDesc.Position = UDim2.new(0.05, 0, 0.6, 0) bDesc.BackgroundTransparency = 1 bDesc.Text = desc bDesc.TextColor3 = Color3.fromRGB(150, 0, 0) bDesc.Font = Enum.Font.Gotham bDesc.TextSize = 10 bDesc.TextXAlignment = Enum.TextXAlignment.Left bDesc.Parent = Frame local Toggle = Instance.new("TextButton") Toggle.Size = UDim2.new(0.2, 0, 0.6, 0) Toggle.Position = UDim2.new(0.75, 0, 0.2, 0) Toggle.BackgroundColor3 = Color3.fromRGB(40, 0, 0) Toggle.Text = "OFF" Toggle.TextColor3 = Color3.fromRGB(255, 255, 255) Toggle.Font = Enum.Font.GothamBold Toggle.TextSize = 10 Toggle.Parent = Frame local tCorner = Instance.new("UICorner") tCorner.Parent = Toggle local active = false Toggle.MouseButton1Click:Connect(function() active = not active Toggle.Text = active and "ON" or "OFF" Toggle.BackgroundColor3 = active and Color3.fromRGB(200, 0, 0) or Color3.fromRGB(40, 0, 0) end) end CreateHack("PS_WALKSPEED", "Override human speed limits") CreateHack("ADMIN_SCAN", "Notify if PSCITYOWNER joins") CreateHack("SWORD_GLITCH", "Enhanced reach & animation") CreateHack("VOID_JUMP", "Infinite vertical mobility") local dragging, dragInput, dragStart, startPos Shadow.InputBegan:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton1 then dragging = true dragStart = input.Position startPos = Shadow.Position end end) Shadow.InputChanged:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseMovement then dragInput = input end end) UserInputService.InputChanged:Connect(function(input) if input == dragInput and dragging then local delta = input.Position - dragStart Shadow.Position = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y) end end) UserInputService.InputEnded:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton1 then dragging = false end end) print("SUPREME PS CITY UI LOADED | WELCOME SIRAPHIT")















































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































